theme.custom_css_code:
.kc-brand-card {
  background: #000000;
  color: #f5f5f5;
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 20px;
  padding: 20px;
  box-sizing: border-box;
  width: 100%;
  max-width: 980px;
  margin: 0 auto;
  font-family: Arial, sans-serif;
  box-shadow: 0 16px 40px rgba(0,0,0,0.35);
}

.kc-table-wrap {
  width: 100%;
  overflow-x: auto;
}

.kc-brand-table {
  width: 100%;
  min-width: 720px;
  border-collapse: collapse;
}

.kc-brand-table td {
  padding: 14px 16px;
  border-bottom: 1px solid rgba(255,255,255,0.08);
  vertical-align: top;
  font-size: 14px;
  line-height: 1.45;
}

.kc-brand-table tr:last-child td {
  border-bottom: 0;
}

.kc-brand-table td:first-child {
  width: 32%;
  color: #b8b8b8;
  font-weight: 600;
}

.kc-brand-table td:last-child {
  color: #ffffff;
}

@media (max-width: 640px) {
  .kc-brand-card {
    padding: 14px;
    border-radius: 16px;
  }

  .kc-brand-table td {
    padding: 12px 12px;
    font-size: 13px;
  }
}
.kc-flow-card {
  background: #000000;
  color: #ffffff;
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 20px;
  padding: 22px;
  box-sizing: border-box;
  width: 100%;
  max-width: 980px;
  margin: 0 auto;
  font-family: Arial, sans-serif;
  box-shadow: 0 16px 40px rgba(0,0,0,0.35);
}

.kc-flow-grid {
  display: grid;
  grid-template-columns: repeat(5, minmax(0, 1fr));
  gap: 14px;
}

.kc-flow-step {
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 18px;
  padding: 16px;
}

.kc-flow-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  margin-bottom: 14px;
}

.kc-flow-num {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 34px;
  height: 34px;
  border-radius: 999px;
  background: rgba(255,255,255,0.08);
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.08em;
}

.kc-flow-time {
  color: #bfbfbf;
  font-size: 12px;
  text-align: right;
  line-height: 1.3;
}

.kc-flow-label {
  font-size: 15px;
  font-weight: 700;
  line-height: 1.35;
  margin-bottom: 12px;
}

.kc-flow-bar {
  height: 12px;
  background: rgba(255,255,255,0.08);
  border-radius: 999px;
  overflow: hidden;
}

.kc-flow-bar span {
  display: block;
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, #ffffff 0%, #8f8f8f 100%);
}

@media (max-width: 900px) {
  .kc-flow-grid {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 560px) {
  .kc-flow-card {
    padding: 14px;
    border-radius: 16px;
  }

  .kc-flow-grid {
    grid-template-columns: 1fr;
  }

  .kc-flow-step {
    padding: 14px;
  }
}
.kc-adv-card {
  background: #000000;
  color: #ffffff;
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 20px;
  padding: 22px;
  box-sizing: border-box;
  width: 100%;
  max-width: 980px;
  margin: 0 auto;
  font-family: Arial, sans-serif;
  box-shadow: 0 16px 40px rgba(0,0,0,0.35);
}

.kc-adv-legend {
  display: flex;
  flex-wrap: wrap;
  gap: 18px;
  margin-bottom: 18px;
  color: #d9d9d9;
  font-size: 13px;
}

.kc-legend-item {
  display: inline-flex;
  align-items: center;
  gap: 8px;
}

.kc-legend-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  display: inline-block;
}

.kc-legend-dot-main {
  background: #ffffff;
}

.kc-legend-dot-market {
  background: #6f6f6f;
}

.kc-adv-chart {
  display: grid;
  gap: 14px;
}

.kc-adv-row {
  display: grid;
  grid-template-columns: 170px minmax(0, 1fr) 92px;
  gap: 16px;
  align-items: center;
}

.kc-adv-name {
  font-size: 14px;
  color: #f3f3f3;
  font-weight: 600;
}

.kc-adv-bars {
  display: grid;
  gap: 8px;
}

.kc-adv-bar {
  height: 12px;
  border-radius: 999px;
  overflow: hidden;
}

.kc-adv-bar span {
  display: block;
  height: 100%;
  border-radius: 999px;
}

.kc-adv-main {
  background: rgba(255,255,255,0.08);
}

.kc-adv-main span {
  background: linear-gradient(90deg, #ffffff 0%, #cfcfcf 100%);
}

.kc-adv-market {
  background: rgba(255,255,255,0.05);
}

.kc-adv-market span {
  background: linear-gradient(90deg, #787878 0%, #525252 100%);
}

.kc-adv-score {
  font-size: 13px;
  color: #bfbfbf;
  text-align: right;
  white-space: nowrap;
}

@media (max-width: 700px) {
  .kc-adv-card {
    padding: 14px;
    border-radius: 16px;
  }

  .kc-adv-row {
    grid-template-columns: 1fr;
    gap: 8px;
  }

  .kc-adv-score {
    text-align: left;
  }
}
